/**
 * @param {number} n
 * @param {number} pos
 * @param {number} k
 * @return {number}
 */
function solve(n, pos, k) {
    const MOD = 10**9 + 7;

    if (k < 0) return 0;

    // 1. Modular Arithmetic Helpers

    /**
     * Computes (base^exp) % MOD
     * @param {number} base
     * @param {number} exp
     * @returns {number}
     */
    const power = (base, exp) => {
        let res = 1;
        base %= MOD;
        while (exp > 0) {
            if (exp % 2 === 1) res = (res * base) % MOD;
            base = (base * base) % MOD;
            exp = Math.floor(exp / 2);
        }
        return res;
    };

    /**
     * Computes modular inverse using Fermat's Little Theorem: a^(M-2) % M
     * @param {number} n
     * @returns {number}
     */
    const modInverse = (n) => {
        return power(n, MOD - 2);
    };

    // 2. Precomputation for Combinations (nCr)

    const MAX_N = n;
    const fact = new Array(MAX_N + 1);
    const invFact = new Array(MAX_N + 1);

    fact[0] = 1;
    for (let i = 1; i <= MAX_N; i++) {
        fact[i] = (fact[i - 1] * i) % MOD;
    }

    invFact[MAX_N] = modInverse(fact[MAX_N]);
    for (let i = MAX_N - 1; i >= 0; i--) {
        invFact[i] = (invFact[i + 1] * (i + 1)) % MOD;
    }

    /**
     * Computes C(n, r) % MOD
     * @param {number} n
     * @param {number} r
     * @returns {number}
     */
    const nCr = (n, r) => {
        if (r < 0 || r > n) return 0;
        if (r === 0 || r === n) return 1;
        if (r > n / 2) r = n - r;

        // nCr = n! / (r! * (n-r)!)
        let numerator = fact[n];
        let denominator = (invFact[r] * invFact[n - r]) % MOD;
        return (numerator * denominator) % MOD;
    };

    // 3. Setup problem parameters

    // L: number of people to the left of pos (indices 0 to pos-1)
    const L = pos;
    // R: number of people to the right of pos (indices pos+1 to n-1)
    const R = n - 1 - pos;

    let K_ways = 0;

    // 4. Summing up possibilities
    // We need k_L + k_R = k

    // k_L must satisfy:
    // 1. 0 <= k_L <= L
    // 2. 0 <= k - k_L <= R  => k - R <= k_L <= k

    const start_kL = Math.max(0, k - R);
    const end_kL = Math.min(k, L);

    for (let kL = start_kL; kL <= end_kL; kL++) {
        const kR = k - kL;

        // Ways to get kL visible from L people: C(L, kL)
        const waysL = nCr(L, kL);

        // Ways to get kR visible from R people: C(R, kR)
        const waysR = nCr(R, kR);

        // Total ways for this split (kL, kR)
        const product = (waysL * waysR) % MOD;

        K_ways = (K_ways + product) % MOD;
    }

    // 5. Final result: Multiply by 2 because the person at 'pos' can choose L or R
    const totalWays = (K_ways * 2) % MOD;

    return totalWays;
}

